const q = $json.query;
if (q['hub.mode'] === 'subscribe' && q['hub.verify_token'] === 'twc_meta_2026') {
  return { challenge: q['hub.challenge'] };
}
throw new Error('Invalid verify token');

// Unpack Meta webhook payload
// Handles both FB Page messages and IG Business DMs
const body = $json.body;
if (!body || !body.entry) return [];

const results = [];
for (const entry of body.entry) {
  const platform = body.object === 'instagram' ? 'IG' : 'FB';
  const messaging = entry.messaging || entry.changes || [];
  for (const event of messaging) {
    // IG webhook uses .value.messages structure
    const msg = event.message || (event.value && event.value.messages && event.value.messages[0]);
    if (!msg || !msg.text) continue; // skip non-text (sticker, attachment)

    const senderId = event.sender?.id || event.value?.contacts?.[0]?.wa_id || '';
    const pageId = event.recipient?.id || entry.id || '';

    // Skip our own messages (echo)
    if (senderId === pageId) continue;
    // Skip if older than 5 min (replay protection)
    const ts = event.timestamp || entry.time || 0;
    if (Date.now() - ts * 1000 > 300000) continue;

    results.push({
      platform,
      sender_id: senderId,
      page_id: pageId,
      message_text: msg.text,
      message_id: msg.mid || msg.id || '',
      timestamp: new Date(ts * 1000).toISOString()
    });
  }
}
return results;

