const raw = $json.content?.[0]?.text || '{}';
let parsed;
try { parsed = JSON.parse(raw); } catch(e) { parsed = { intent:'unknown', priority:'low', topic:'parse error', reply:'Chào bạn 👋 Bạn đang quan tâm đến AI training cho cá nhân hay cho team nhỉ?', cta:'qualify' }; }
return {
  ...$('extract_messages').item.json,
  intent: parsed.intent || 'unknown',
  priority: parsed.priority || 'low',
  topic: parsed.topic || '',
  reply_text: parsed.reply || '',
  cta: parsed.cta || 'qualify'
};

